        if not fname.endswith('.geo'):
            fname += '.geo'

        curr_fig = self.fig
        curr_ax = self.ax
        curr_line_ani = self.line_ani

        curr_data = self.data
        if isinstance(curr_data, pd.DataFrame):
            data_out_fmt = curr_data.to_dict('list')
        else:
            data_out_fmt = curr_data

        try:
            self.fig = self.ax = self.line_ani = None
